const raw = $json;
// Handle GET (query params) and POST (body)
const agentName = (raw.query && raw.query.agent_name)
  || (raw.body && raw.body.agent_name)
  || raw.agent_name
  || 'haiku_self_critic';
return [{json: {agent_name: agentName}}];

const raw = $json;
const arr = Array.isArray(raw) ? raw : [raw];
const agent = arr.length > 0 ? arr[0] : {};
return [{
  json: {
    agent_info: agent,
    agent_name: agent.agent_name || $('Parse Input').item.json.agent_name,
    workflow_id: agent.workflow_id || null,
    status: agent.status || 'unknown',
    telegram_command: agent.telegram_command || null
  }
}];

// Always returns exactly 1 item — fixes n8n 0-item chain-stop bug
const agentNode = $('Extract Agent').first().json;
const agentName = agentNode.agent_name;
const workflowId = agentNode.workflow_id;
const agentStatus = agentNode.status;
const apiKey = '{{CREDENTIAL_REDACTED}}';
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey };

let outputs = [];
try {
  const url = `https://cihbfubghytzqrpffgcq.supabase.co/rest/v1/experimental_outputs?agent_name=eq.${encodeURIComponent(agentName)}&order=created_at.desc&limit=3`;
  const resp = await fetch(url, { headers });
  const data = await resp.json();
  outputs = Array.isArray(data) ? data : [];
} catch(e) { outputs = []; }

let auditEvidence = [];
if (outputs.length === 0 && agentStatus === 'active' && workflowId) {
  try {
    const auditUrl = `https://cihbfubghytzqrpffgcq.supabase.co/rest/v1/audit_log?target=like.n8n_workflow:${encodeURIComponent(workflowId)}*&order=timestamp.desc&limit=5`;
    const auditResp = await fetch(auditUrl, { headers });
    const auditData = await auditResp.json();
    auditEvidence = Array.isArray(auditData) ? auditData : [];
  } catch(e) { auditEvidence = []; }
  try {
    const n8nKey = '{{CREDENTIAL_REDACTED}}';
    const execUrl = `http://localhost:5678/api/v1/executions?workflowId=${workflowId}&limit=3`;
    const execResp = await fetch(execUrl, { headers: { 'X-N8N-API-KEY': n8nKey } });
    const execData = await execResp.json();
    const executions = Array.isArray(execData.data) ? execData.data : [];
    if (executions.length > 0) {
      auditEvidence = auditEvidence.concat(executions.map(e => ({source:'n8n_execution',status:e.status,startedAt:e.startedAt,stoppedAt:e.stoppedAt,mode:e.mode})));
    }
  } catch(e) {}
}

return [{json: {outputs, auditEvidence, _has_outputs: outputs.length > 0, _is_production: agentStatus === 'active'}}];

const agentNode = $('Extract Agent').first().json;
const agentInfo = agentNode.agent_info || {};
const agentName = agentNode.agent_name || 'unknown';
const telegramCommand = agentNode.telegram_command;
const agentStatus = agentNode.status || 'unknown';
const outputsArr = $json.outputs || [];
const auditEvidence = $json.auditEvidence || [];
const isProduction = $json._is_production || false;

function flattenContent(content, maxLen) {
  if (!content) return '(empty)';
  if (typeof content === 'string') return content.slice(0, maxLen);
  if (typeof content === 'object') {
    const STRIP_KEYS = ['connection', '__type', '_meta', 'pairedItem', 'json'];
    const clean = {};
    for (const [k, v] of Object.entries(content)) {
      if (!STRIP_KEYS.includes(k)) clean[k] = v;
    }
    return JSON.stringify(clean).slice(0, maxLen);
  }
  return String(content).slice(0, maxLen);
}

let evidenceSection;
if (outputsArr.length > 0) {
  evidenceSection = outputsArr.slice(0,3).map((o, i) => {
    const contentStr = flattenContent(o.content, 400);
    return `Output ${i+1} [${o.experiment_id||'?'}] type=${o.output_type||'?'} confidence=${o.confidence||'?'}:\n${contentStr}`;
  }).join('\n\n');
} else if (isProduction && auditEvidence.length > 0) {
  const auditStr = auditEvidence.slice(0,5).map(e => {
    if (e.source === 'n8n_execution') return `n8n execution: status=${e.status} started=${e.startedAt} mode=${e.mode}`;
    return `Audit: action=${e.action||'?'} target=${e.target||'?'} at=${e.timestamp||'?'}`;
  }).join('\n');
  evidenceSection = `This is an active production agent that sends output to Telegram (command: ${telegramCommand || 'none'}).\nNo experimental_outputs expected — it writes to Telegram. Evidence from execution history:\n${auditStr}`;
} else if (isProduction) {
  evidenceSection = `This is an active production agent (telegram_command: ${telegramCommand || 'none'}).\nIt sends output to Telegram rather than experimental_outputs. No recent execution records found.\nEvaluate based on description and architecture.`;
} else {
  evidenceSection = 'No outputs recorded yet — agent has not been run or is newly registered.';
}

// Status-aware recommendation options
const recOptions = isProduction
  ? 'maintain (keep running as-is)|needs_work (has issues requiring fixes)|retire (should be decommissioned)'
  : 'promote (ready for production)|keep_sandbox (promising but needs more testing)|needs_work (has issues requiring fixes)|retire (concept not worth pursuing)';

const prompt = `Evaluate this AADP agent on 4 pillars. Return ONLY valid JSON.\n\nAGENT PROFILE:\nName: ${agentInfo.display_name || agentName}\nType: ${agentInfo.agent_type || 'unknown'}\nStatus: ${agentStatus}\nDescription: ${agentInfo.description || 'No description available'}\nData Sources: ${JSON.stringify(agentInfo.data_sources || [])}\nSchedule: ${agentInfo.schedule || 'on_demand'}\nTelegram Command: ${telegramCommand || 'none'}\n\nEVIDENCE (${outputsArr.length} experimental outputs, ${auditEvidence.length} audit/exec records):\n${evidenceSection}\n\nEVALUATION PILLARS:\n1. behavior_consistency — Does output/evidence match stated description/purpose?\n2. output_quality — Is content well-formed, factually plausible, valuable to Bill?\n3. reliability — Would it handle errors/edge cases gracefully?\n4. integration_fit — Does it use AADP infrastructure and conventions well?\n\nIMPORTANT: Active production agents (status=active) are proven working — do not penalize for missing experimental_outputs.\n\nVALID RECOMMENDATION VALUES for this agent (status=${agentStatus}):\n${recOptions}\n\nReturn this exact JSON (scores 1-5, 1=poor 5=excellent):\n{"behavior_consistency":{"score":0,"notes":""},"output_quality":{"score":0,"notes":""},"reliability":{"score":0,"notes":""},"integration_fit":{"score":0,"notes":""},"overall_score":0,"recommendation":"one of the valid values above","summary":""}`;

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 700,
  messages: [{role: 'user', content: prompt}]
};
return [{json: {haiku_body: JSON.stringify(body), agent_name: agentName}}];

const haikuResp = $json;
const buildNode = $('Build Eval Prompt').first().json;
const agentName = buildNode.agent_name || 'unknown';

const raw = (haikuResp.content && haikuResp.content[0]) ? haikuResp.content[0].text : '{}';
let parsed = {
  behavior_consistency:{score:3,notes:'parse_failed'},
  output_quality:{score:3,notes:'parse_failed'},
  reliability:{score:3,notes:'parse_failed'},
  integration_fit:{score:3,notes:'parse_failed'},
  overall_score:3, recommendation:'keep_sandbox', summary:'Evaluation incomplete'
};
try {
  const s = raw.indexOf('{');
  const e = raw.lastIndexOf('}');
  if (s >= 0 && e > s) parsed = JSON.parse(raw.slice(s, e+1));
} catch(err) {}

const today = new Date().toISOString().slice(0,10);
const record = {
  agent_name: agentName,
  experiment_id: `4pillars_eval_${agentName}_${today}`,
  output_type: '4pillars_evaluation',
  content: parsed,
  confidence: ((parsed.overall_score || 3) / 5.0),
  promoted: false,
  reviewed_by_bill: false
};
return [{json: {body_json: JSON.stringify(record), eval_summary: parsed.summary || '', recommendation: parsed.recommendation || '', overall_score: parsed.overall_score || 0}}];

